@RestController
public class LogoutController {
    
    private static final Set<String> ALLOWED_REDIRECTS = Set.of(
        "/login", 
        "/dashboard", 
        "/home",
        "/sso/login"
    );
    
    @PostMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        // Invalidate session
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }
        
        // Clear any authentication cookies
        Cookie[] cookies = request.getCookies();
        if (cookies != null) {
            for (Cookie cookie : cookies) {
                if (cookie.getName().startsWith("JSESSIONID") || 
                    cookie.getName().startsWith("AUTH_TOKEN")) {
                    cookie.setValue("");
                    cookie.setPath("/");
                    cookie.setMaxAge(0);
                    response.addCookie(cookie);
                }
            }
        }
        
        // Validate redirect URL
        String nextUrl = request.getParameter("next");
        String redirectUrl = validateRedirectUrl(nextUrl);
        
        // Perform redirect
        response.sendRedirect(redirectUrl);
    }
    
    private String validateRedirectUrl(String nextUrl) {
        if (nextUrl == null || nextUrl.trim().isEmpty()) {
            return "/login";
        }
        
        // Check if it's a relative path and in allowlist
        if (nextUrl.startsWith("/") && ALLOWED_REDIRECTS.contains(nextUrl)) {
            return nextUrl;
        }
        
        // Check if it's a valid relative path (not absolute URL)
        try {
            URI uri = URI.create(nextUrl);
            if (uri.isAbsolute()) {
                // If absolute URL, check if it's from allowed domains
                String host = uri.getHost();
                // Add domain validation logic here if needed
                return "/login"; // Default fallback
            } else {
                // Relative path - validate against allowlist
                if (ALLOWED_REDIRECTS.contains(nextUrl)) {
                    return nextUrl;
                }
                return "/login";
            }
        } catch (Exception e) {
            return "/login";
        }
    }
}